INSERT OR REPLACE INTO products (id, title, description, price, sale_price, image_url, additional_images, availability, condition, category, slug, tags, download_path, woo_product_id) VALUES ('6209', 'Introduction to Maternity and Pediatric Nursing 7th edition by Leifer Test Bank', 'This test bank complements Introduction to Maternity and Pediatric Nursing, 7th Edition. It includes comprehensive practice questions to support nursing students in mastering essential concepts in maternity and pediatric nursing care. Key Features: Based on the 7th edition content Covers maternal health, newborn care, child development, and pediatric nursing principles Ideal for exam preparation and clinical knowledge reinforcement Suitable for nursing students specializing in maternity and pediatrics', '17', '14', 'https://nurstestbank.com/uploads/images/6209/main.jpg', '["https://nurstestbank.com/uploads/images/6209/img_1.jpg","https://nurstestbank.com/uploads/images/6209/img_2.jpg","https://nurstestbank.com/uploads/images/6209/img_3.jpg","https://nurstestbank.com/uploads/images/6209/img_4.jpg"]', 'in_stock', 'new', 'Nursing', 'introduction-to-maternity-and-pediatric-nursing-7th-edition-by-leifer-test-bank-6209', '[]', 'https://drive.google.com/file/d/1dcRaoKWDRXnFM23OTP6fcb_vpoRgdD0b/view?usp=drive_link', '6209');
INSERT OR REPLACE INTO products (id, title, description, price, sale_price, image_url, additional_images, availability, condition, category, slug, tags, download_path, woo_product_id) VALUES ('6332', 'Introduction to Maternity and Pediatric Nursing 9th Edition Leifer Test Bank', 'This Test Bank is developed to accompany the 9th Edition of Introduction to Maternity and Pediatric Nursing by Leifer. It includes a comprehensive set of exam-style questions that help nursing students master the essential concepts of maternal and pediatric care. Key topics include: • Reproductive health and the childbearing process • Newborn assessment and family-centered care • Pediatric growth, development, and health promotion • Nursing management of childhood illnesses and conditions • Patient safety, communication, and ethical care in maternity and pediatrics This resource supports nursing students in building strong clinical knowledge and preparing effectively for coursework, exams, and practical application. Includes: • Multiple-choice and case-based questions • Fully aligned with the 9th Edition textbook content', '20', '16', 'https://nurstestbank.com/uploads/images/6332/main.jpg', '["https://nurstestbank.com/uploads/images/6332/img_1.jpg","https://nurstestbank.com/uploads/images/6332/img_2.jpg","https://nurstestbank.com/uploads/images/6332/img_3.jpg","https://nurstestbank.com/uploads/images/6332/img_4.jpg","https://nurstestbank.com/uploads/images/6332/img_5.jpg","https://nurstestbank.com/uploads/images/6332/img_6.jpg","https://nurstestbank.com/uploads/images/6332/img_7.jpg","https://nurstestbank.com/uploads/images/6332/img_8.jpg"]', 'in_stock', 'new', 'Nursing', 'introduction-to-maternity-and-pediatric-nursing-9th-edition-leifer-test-bank-6332', '[]', 'https://drive.google.com/file/d/15P0ufX2GX9_uESrtUeuI5fvE-wxwPbfa/view?usp=drive_link', '6332');
