INSERT OR REPLACE INTO products (id, title, description, price, sale_price, image_url, additional_images, availability, condition, category, slug, tags, download_path, woo_product_id) VALUES ('6406', 'Pharmacology and the Nursing Process 9th Edition by Lilley Test Bank', 'This test bank complements Pharmacology and the Nursing Process, 9th Edition by Linda Lane Lilley, Shelly Rainforth Collins, and Julie S. Snyder. It provides a comprehensive set of practice questions to help nursing students master concepts related to pharmacology and the nursing process. Key Features: Aligned with the 9th edition content Covers drug classifications, mechanisms of action, therapeutic uses, and nursing interventions Ideal for exam preparation and clinical knowledge reinforcement Suitable for nursing students and healthcare professionals', '17', '14', 'https://nurstestbank.com/uploads/images/6406/main.jpg', '["https://nurstestbank.com/uploads/images/6406/img_1.jpg","https://nurstestbank.com/uploads/images/6406/img_2.jpg","https://nurstestbank.com/uploads/images/6406/img_3.jpg","https://nurstestbank.com/uploads/images/6406/img_4.jpg"]', 'in_stock', 'new', 'Nursing', 'pharmacology-and-the-nursing-process-9th-edition-by-lilley-test-bank-6406', '[]', NULL, '6406');
