INSERT OR REPLACE INTO products (id, title, description, price, sale_price, image_url, additional_images, availability, condition, category, slug, tags, download_path, woo_product_id) VALUES ('6179', 'Primary Care: Art and Science of Advanced Practice Nursing - An Interprofessional Approach 5th edition by Dunphy Test Bank', 'This test bank is based on Primary Care: The Art and Science of Advanced Practice Nursing, 5th Edition by Dunphy. It offers a broad range of practice questions designed to support advanced practice nursing students in mastering primary care concepts and clinical decision-making. Key Features: Covers major topics from the 5th edition Supports preparation for exams and clinical application Designed for nurse practitioners and advanced practice students Focuses on interprofessional care, diagnostics, and patient management', '17', '14', 'https://nurstestbank.com/uploads/images/6179/main.jpg', '["https://nurstestbank.com/uploads/images/6179/img_1.jpg","https://nurstestbank.com/uploads/images/6179/img_2.jpg","https://nurstestbank.com/uploads/images/6179/img_3.jpg","https://nurstestbank.com/uploads/images/6179/img_4.jpg"]', 'in_stock', 'new', 'Nursing', 'primary-care-art-and-science-of-advanced-practice-nursing-an-interprofessional-approach-5th-edition-by-dunphy-test-bank-6179', '[]', 'https://nurstestbank.com/uploads/downloads/view', '6179');
INSERT OR REPLACE INTO products (id, title, description, price, sale_price, image_url, additional_images, availability, condition, category, slug, tags, download_path, woo_product_id) VALUES ('6425', 'Primary Care: The Art and Science of Advanced Practice Nursing – An Interprofessional Approach, 6th Edition by Debera J. Dunphy Test Bank', 'This Test Bank is designed to accompany the 6th Edition of Primary Care: The Art and Science of Advanced Practice Nursing – An Interprofessional Approach by Debera J. Dunphy. It includes a comprehensive collection of exam-style questions that focus on advanced clinical reasoning, patient management, and interprofessional collaboration. Key topics include: • Evidence-based assessment and diagnosis in primary care • Health promotion, prevention, and chronic disease management • Pharmacologic and non-pharmacologic interventions • Culturally competent and patient-centered care • Ethical decision-making and interprofessional teamwork This resource supports advanced practice nursing students in building confidence for coursework, certification exams, and clinical application. Includes: • Multiple-choice and scenario-based questions • Fully aligned with the 6th Edition textbook content', '20', '16', 'https://nurstestbank.com/uploads/images/6425/main.jpg', '["https://nurstestbank.com/uploads/images/6425/img_1.jpg","https://nurstestbank.com/uploads/images/6425/img_2.jpg","https://nurstestbank.com/uploads/images/6425/img_3.jpg","https://nurstestbank.com/uploads/images/6425/img_4.jpg","https://nurstestbank.com/uploads/images/6425/img_5.jpg","https://nurstestbank.com/uploads/images/6425/img_6.jpg"]', 'in_stock', 'new', 'Nursing', 'primary-care-the-art-and-science-of-advanced-practice-nursing-an-interprofessional-approach-6th-edition-by-debera-j-dunphy-test-bank-6425', '[]', 'https://drive.google.com/file/d/1o78dFdNpd8gZFBwWpizZpljDjLuVlKSd/view?usp=sharing', '6425');
