INSERT OR REPLACE INTO products (id, title, description, price, sale_price, image_url, additional_images, availability, condition, category, slug, tags, download_path, woo_product_id) VALUES ('6433', 'Success in Practical/Vocational Nursing, 8th Edition by Knecht Test Bank', 'This test bank complements Success in Practical/Vocational Nursing, 8th Edition by Patricia Knecht. It provides a comprehensive set of practice questions to help nursing students master concepts related to practical and vocational nursing. Key Features: Aligned with the 8th edition content Covers personal resources, academic resources, community resources, and the evolution of practical/vocational nursing Ideal for exam preparation and clinical knowledge reinforcement Suitable for nursing students and educators', '17', '14', 'https://nurstestbank.com/uploads/images/6433/main.jpg', '["https://nurstestbank.com/uploads/images/6433/img_1.jpg","https://nurstestbank.com/uploads/images/6433/img_2.jpg","https://nurstestbank.com/uploads/images/6433/img_3.jpg","https://nurstestbank.com/uploads/images/6433/img_4.jpg"]', 'in_stock', 'new', 'Nursing', 'success-in-practicalvocational-nursing-8th-edition-by-knecht-test-bank-6433', '[]', NULL, '6433');
